+            recovery(false, None, ""),
+            1,
+        )).unwrap();
+        assert!(e.severity.is_fatal());
+        assert!(!e.recovery.retryable);
+    }
+
+    #[test]
+    fn reject_invalid_namespace() {
+        let mut r = ErrorCodeRegistry::new();
+        let err = r.register(&reg(
+            "BAD_PREFIX_FOO",
+            Severity::Transient,
