+        )).unwrap_err();
+        assert_eq!(err.code(), "ECR_INVALID_NAMESPACE");
+    }
+
+    #[test]
+    fn reject_unknown_subsystem() {
+        let mut r = ErrorCodeRegistry::new();
+        let err = r.register(&reg(
+            "FRANKEN_UNKNOWN_FOO",
+            Severity::Transient,
