+#[derive(Debug, Clone, PartialEq)]
+pub enum GuardrailViolation {
+    SizeExceeded { actual: u64, limit: u64 },
+    DepthExceeded { actual: u32, limit: u32 },
+    CpuExceeded { actual: u64, limit: u64 },
+    MalformedFrame { reason: String },
+}
+
