+        r.register(&reg("franken.protocol.x", MetricType::Counter, &["a"], 1)).unwrap();
+        let s = r.register(&reg("franken.protocol.x", MetricType::Gauge, &["b"], 2)).unwrap();
+        assert_eq!(s.metric_type, MetricType::Gauge);
