+        assert!(codes.contains(&"TNS_FROZEN_CONFLICT"));
+        assert!(codes.contains(&"TNS_ALREADY_DEPRECATED"));
+        assert!(codes.contains(&"TNS_NOT_FOUND"));
+    }
